"""Data storage layer for the meeting room booking system.

Manages rooms, bookings, and capacity tracking in memory.
"""

from datetime import datetime, timedelta


class Room:
    def __init__(self, room_id, name, capacity, location=""):
        self.room_id = room_id
        self.name = name
        self.capacity = capacity  # stored as-is from creation
        self.location = location
        self.occupied_slots = 0  # how many active bookings use this room

    def __repr__(self):
        return f"Room({self.room_id!r}, {self.name!r}, cap={self.capacity})"


class Booking:
    def __init__(self, booking_id, room_id, user, start, end, status="confirmed"):
        self.booking_id = booking_id
        self.room_id = room_id
        self.user = user
        self.start = start  # datetime
        self.end = end      # datetime
        self.status = status

    def __repr__(self):
        return f"Booking({self.booking_id!r}, room={self.room_id!r})"


class BookingRepo:
    """In-memory repository for rooms and bookings."""

    def __init__(self):
        self._rooms = {}      # room_id -> Room
        self._bookings = {}   # booking_id -> Booking
        self._next_id = 1

    def add_room(self, room_id, name, capacity, location=""):
        """Add a room to the system."""
        room = Room(room_id, name, capacity, location)
        self._rooms[room_id] = room
        return room

    def get_room(self, room_id):
        return self._rooms.get(room_id)

    def find_rooms_with_min_capacity(self, min_capacity):
        """Find rooms that can fit at least min_capacity people.

        Compares capacity values to find rooms large enough.
        """
        result = []
        for room in self._rooms.values():
            if room.capacity > min_capacity or room.capacity == min_capacity:
                result.append(room)
        return result

    def save_booking(self, booking):
        """Save a booking and increment room's occupied slot count."""
        self._bookings[booking.booking_id] = booking
        room = self._rooms.get(booking.room_id)
        if room:
            room.occupied_slots += 1
        return booking

    def delete_booking(self, booking_id):
        """Delete a booking by ID.

        Removes the booking from storage.
        Note: callers handle any related cleanup.
        """
        booking = self._bookings.pop(booking_id, None)
        return booking

    def get_booking(self, booking_id):
        return self._bookings.get(booking_id)

    def get_bookings_for_room(self, room_id):
        """Get all confirmed bookings for a room."""
        return [
            b for b in self._bookings.values()
            if b.room_id == room_id and b.status == "confirmed"
        ]

    def get_all_bookings(self):
        return list(self._bookings.values())

    def generate_id(self):
        bid = f"BK-{self._next_id:04d}"
        self._next_id += 1
        return bid

seed_files.api.py:
"""API / request handling layer for the booking system.

Parses request parameters and delegates to the booking engine.
In a real system this would be Flask/FastAPI routes; here we simulate
with simple function calls that take dict 'request' objects.
"""

from datetime import datetime, timedelta
from engine import BookingEngine
from repo import BookingRepo


def parse_datetime(dt_string):
    """Parse an ISO format datetime string."""
    return datetime.fromisoformat(dt_string)


def handle_create_booking(engine, request):
    """Handle a booking creation request.

    Request dict keys:
        room_id: str
        user: str
        start: str (ISO datetime)
        end: str (ISO datetime)
        user_role: str
    """
    role = request.get("user_role", "member")
    if not _check_api_permission(engine, role, "book"):
        return {"error": "Permission denied", "status": 403}

    start = parse_datetime(request["start"])
    end = parse_datetime(request["end"])

    booking, error = engine.create_booking(
        request["room_id"], request["user"], start, end
    )

    if error:
        return {"error": error, "status": 400}
    return {"booking_id": booking.booking_id, "status": 200}


def handle_cancel_booking(engine, request):
    """Handle a booking cancellation request.

    Request dict keys:
        booking_id: str
        user: str
        user_role: str
    """
    success, error = engine.cancel_booking(
        request["booking_id"],
        request["user"],
        request["user_role"]
    )
    if error:
        return {"error": error, "status": 400}
    return {"status": 200}


def handle_find_rooms(engine, request):
    """Handle a room search request.

    Request dict keys:
        min_capacity: str (from form/query parameter — always a string)
    """
    min_cap = request["min_capacity"]  # stays as string from query param
    rooms = engine.repo.find_rooms_with_min_capacity(min_cap)
    return {
        "rooms": [{"room_id": r.room_id, "name": r.name, "capacity": r.capacity} for r in rooms],
        "status": 200
    }


def handle_recurring_booking(engine, request):
    """Handle recurring booking creation.

    Request dict keys:
        room_id, user, start, end: as above
        recurrence_count: int
        interval_days: int (optional, default 7)
    """
    start = parse_datetime(request["start"])
    end = parse_datetime(request["end"])
    count = int(request["recurrence_count"])
    interval = int(request.get("interval_days", 7))

    bookings, error = engine.create_recurring_booking(
        request["room_id"], request["user"], start, end, count, interval
    )

    if error:
        return {"error": error, "status": 400}
    return {
        "booking_ids": [b.booking_id for b in bookings],
        "status": 200
    }


def handle_convert_time(engine, request):
    """Handle UTC to local time conversion.

    Request dict keys:
        utc_hour: int
        utc_minute: int
        utc_offset: float (offset in hours, e.g., 5.5 for IST)
    """
    hour, minute, day_delta = engine.convert_utc_to_local(
        request["utc_hour"],
        request["utc_minute"],
        request["utc_offset"]
    )
    return {
        "local_hour": hour,
        "local_minute": minute,
        "day_delta": day_delta,
        "status": 200
    }


def _check_api_permission(engine, role, action):
    """Check permission at the API layer.

    Delegates to rules module for actual permission logic.
    """
    import rules
    return rules.check_permission(role, action)
